desc:Lo-Fi Bitcrusher
slider1:16<1,16,1>Bit Depth
slider2:1<1,64,1>Sample Rate Divisor

@slider
quant = 2^slider1;
divisor = slider2;

@sample
counter += 1;
counter >= divisor ? (
  hold0 = floor(spl0 * quant + 0.5) / quant;
  hold1 = floor(spl1 * quant + 0.5) / quant;
  counter = 0;
);
spl0 = hold0;
spl1 = hold1;

desc:Stereo Tremolo
slider1:4<0.1,20,0.1>Rate (Hz)
slider2:50<0,100,1>Depth (%)

@slider
rate = slider1;
depth = slider2 / 100;

@sample
phase += rate * 2 * $pi / srate;
phase >= 2 * $pi ? phase -= 2 * $pi;
mod = 1 - depth * (0.5 + 0.5 * sin(phase));
spl0 *= mod;
spl1 *= mod;

desc:Output Gain
slider1:0<-60,12,0.1>Gain (dB)

@slider
gain = 10^(slider1/20);

@sample
spl0 *= gain;
spl1 *= gain;
